fn fill_icon(class: &str, path: &str) -> Markup {
    raw_svg(
        class,
        "0 0 256 256",
        &format!(r#"<path d="{path}" fill="currentColor"/>"#),
    )
}

fn stroke_icon(class: &str, inner: &str) -> Markup {
    PreEscaped(format!(
        r#"<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 256 256" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="24" class="{class}" aria-hidden="true" focusable="false">{inner}</svg>"#
    ))
}

fn raw_svg(class: &str, view_box: &str, inner: &str) -> Markup {
    PreEscaped(format!(
        r#"<svg xmlns="http://www.w3.org/2000/svg" viewBox="{view_box}" class="{class}" aria-hidden="true" focusable="false">{inner}</svg>"#
    ))
}
